279	func endpointProviderEntry(endpoint ddxconfig.AgentEndpoint, index int) (string, agentlib.ServiceProviderEntry, error) {
280		providerType := strings.ToLower(strings.TrimSpace(endpoint.Type))
281		baseURL := strings.TrimSpace(endpoint.BaseURL)
282		if baseURL == "" {
283			if endpoint.Host == "" || endpoint.Port == 0 {
284				return "", agentlib.ServiceProviderEntry{}, fmt.Errorf("agent.endpoints[%d]: base_url or host+port is required", index)
285			}
286			baseURL = fmt.Sprintf("http://%s:%d/v1", endpoint.Host, endpoint.Port)
287		}
288		if providerType == "" {
289			providerType = inferEndpointProviderType(baseURL, endpoint.Port)
290		}
291		if providerType == "" {
292			return "", agentlib.ServiceProviderEntry{}, fmt.Errorf("agent.endpoints[%d]: type is required when it cannot be inferred", index)
293		}
294	
295		name := endpointProviderName(providerType, baseURL, endpoint, index)
296		return name, agentlib.ServiceProviderEntry{
297			Type:    providerType,
298			BaseURL: baseURL,
299			APIKey:  endpoint.APIKey,
300		}, nil
301	}
