303	func inferEndpointProviderType(baseURL string, port int) string {
304		low := strings.ToLower(baseURL)
305		switch {
306		case strings.Contains(low, "openrouter.ai"):
307			return "openrouter"
308		case strings.Contains(low, "openai.com"):
309			return "openai"
310		case strings.Contains(low, ":1235") || port == 1235:
311			return "omlx"
312		case strings.Contains(low, ":11434") || port == 11434:
313			return "ollama"
314		case strings.Contains(low, ":1234") || port == 1234:
315			return "lmstudio"
316		default:
317			return ""
318		}
319	}
