321	func endpointProviderName(providerType, baseURL string, endpoint ddxconfig.AgentEndpoint, index int) string {
322		host := endpoint.Host
323		port := endpoint.Port
324		if u, err := url.Parse(baseURL); err == nil {
325			if host == "" {
326				host = u.Hostname()
327			}
328			if port == 0 {
329				if p := u.Port(); p != "" {
330					if n, err := strconv.Atoi(p); err == nil {
331						port = n
332					}
333				}
334			}
335		}
336		parts := []string{providerType}
337		if host != "" {
338			parts = append(parts, host)
339		}
340		if port != 0 {
341			parts = append(parts, strconv.Itoa(port))
342		}
343		if len(parts) == 1 {
344			parts = append(parts, strconv.Itoa(index+1))
345		}
346		return sanitizeEndpointName(strings.Join(parts, "-"))
347	}
