349	func sanitizeEndpointName(s string) string {
350		s = strings.ToLower(strings.TrimSpace(s))
351		var b strings.Builder
352		lastDash := false
353		for _, r := range s {
354			keep := unicode.IsLetter(r) || unicode.IsDigit(r)
355			if keep {
356				b.WriteRune(r)
357				lastDash = false
358				continue
359			}
360			if !lastDash {
361				b.WriteByte('-')
362				lastDash = true
363			}
364		}
365		out := strings.Trim(b.String(), "-")
366		if out == "" {
367			return "endpoint"
368		}
369		return out
370	}
