372	func endpointHasLiveModels(ctx context.Context, baseURL, apiKey string) bool {
373		probeCtx, cancel := context.WithTimeout(ctx, 2*time.Second)
374		defer cancel()
375	
376		req, err := http.NewRequestWithContext(probeCtx, http.MethodGet, strings.TrimRight(baseURL, "/")+"/models", nil)
377		if err != nil {
378			return false
379		}
380		if apiKey != "" {
381			req.Header.Set("Authorization", "Bearer "+apiKey)
382		}
383		resp, err := http.DefaultClient.Do(req)
384		if err != nil {
385			return false
386		}
387		defer resp.Body.Close() //nolint:errcheck
388		if resp.StatusCode < 200 || resp.StatusCode >= 300 {
389			return false
390		}
391	
392		var payload struct {
393			Data []struct {
394				ID string `json:"id"`
395			} `json:"data"`
396		}
397		if err := json.NewDecoder(resp.Body).Decode(&payload); err != nil {
398			return false
399		}
400		for _, model := range payload.Data {
401			if strings.TrimSpace(model.ID) != "" {
402				return true
403			}
404		}
405		return false
406	}
